import "./Article.css";

export default function SNArticle() {
  return (
    <main className="article-page">
      <article className="article-container">

        <h1 className="article-title">S vs N</h1>

        <img
          src="/svsn.png"
          alt="Sensing vs Intuition"
          className="article-hero"
        />

        <p className="lead">
          Sensing (S) და Intuition (N) აღწერს იმას&#44; როგორ იღებს და ამუშავებს ადამიანი
          ინფორმაციას გარემოდან&#46; ეს განზომილება არ ეხება ინტელექტის დონეს&#44; არამედ
          ყურადღების ფოკუსს &#8210; რას ამჩნევს ადამიანი პირველ რიგში და როგორ აყალიბებს
          რეალობის სურათს&#46;
        </p>

        <h3>იუნგის თეორიული საფუძველი</h3>
        <p>
          კარლ იუნგის მიხედვით&#44;  გრძნობადი აღქმა (Sensation) და ინტუიცია (Intuition)
          წარმოადგენს ინფორმაციის მიღების ორ განსხვავებულ ფსიქოლოგიურ ფუნქციას&#46;
          Sensing (S) კონცენტრირებულია იმაზე&#44;  რაც პირდაპირ აღიქმება &#8210; ფაქტები&#44; 
          დეტალები და კონკრეტული გამოცდილება&#46;
          Intuition (N) კი მიმართულია იმაზე&#44;  რაც არ ჩანს პირდაპირ &#8210; შესაძლებლობები&#44; 
          კავშირები და მომავლის პოტენციალი&#46;
          იუნგი ამ განსხვავებას მიიჩნევდა ფსიქოლოგიურად ფუნდამენტურად და არა
          სწავლით ან აღზრდით ჩამოყალიბებულ ჩვევად&#46;
        </p>

        <h3>თანამედროვე ფსიქოლოგიური ხედვა</h3>
        <p>
          თანამედროვე პიროვნების ფსიქოლოგიაში ეს განსხვავება აიხსნება როგორც
          ინფორმაციის დამუშავების სტილი და არა ინტელექტუალური უპირატესობა&#46;
        </p>
        <ul>
          <li>
            <strong>S ტიპები</strong> უფრო მეტად ენდობიან გამოცდილებას&#44;
            პრაქტიკულ მონაცემებს და კონკრეტულ მაგალითებს&#46;
          </li>
          <li>
            <strong>N ტიპები</strong> ყურადღებას ამახვილებენ მთლიან სურათზე&#44;
            აბსტრაქტულ იდეებსა და ტენდენციებზე&#46;
          </li>
          <li>
            კვლევები აჩვენებს&#44; რომ ეს განსხვავება გავლენას ახდენს სწავლაზე&#44;
            პრობლემების გადაჭრაზე და გადაწყვეტილებების მიღებაზე&#46;
          </li>
        </ul>

        <p>
          მნიშვნელოვანია აღინიშნოს&#44; რომ Sensing არ ნიშნავს წარმოსახვის ნაკლებობას,
          ხოლო Intuition &#8210; ფაქტების იგნორირებას&#46;
          ორივე სტილი აუცილებელია ეფექტური აზროვნებისთვის &#8210; ერთი ამყარებს
          რეალობას&#44; მეორე კი ხსნის ახალ შესაძლებლობებს&#46;
          S და N წარმოადგენს კოგნიტურ განსხვავებას და არა უპირატესობას&#46;
          ფსიქოლოგიური ეფექტიანობა იზრდება მაშინ&#44; როდესაც ადამიანი აცნობიერებს
          საკუთარ აღქმის სტილს და სწავლობს მის შეგნებულ გამოყენებას &#8210;
          სწავლისას&#44; მუშაობისას და ურთიერთობებში&#46;
        </p>

        <h3>წყაროები</h3>
        <ul className="sources">
          <li>Carl Jung (1921)  Psychological Types</li>
          <li>Myers & Myers (1995)  Gifts Differing</li>
          <li>McCrae & Costa (1999)  A Five-Factor Theory of Personality</li>
          <li>APA Dictionary of Psychology  Cognitive Styles</li>
          <li>Dario Nardi (2011)  Neuroscience of Personality</li>
        </ul>

      </article>
    </main>
  );
}
